class MessageStore {
    private val mutex = Mutex()
    private val items = mutableMapOf<String, Message>()

    suspend fun applyAck(clientId: String, serverId: String, status: Status) = mutex.withLock {
        val old = items[clientId] ?: return@withLock
        val next = old.copy(serverId = old.serverId ?: serverId, status = maxOf(old.status, status))
        items[clientId] = next
    }
}

private val _state = MutableStateFlow(ChatState())
fun updateMessage(value: Message) {
    _state.update { state -> state.copy(messages = state.messages.upsert(value)) }
}
